# ─── Paires de colonnes fusionnées dans le template ──────────────────────────
# (découvertes par analyse du template vierge — ne pas modifier)
ALL_MERGE_PAIRS = []
JOURS_COLS      = [2, 18, 38, 54]  # valeur par défaut, recalculée après chargement du template

def _detect_jours_cols(ws):
    """Détecte dynamiquement les colonnes de dates (Lundi/Mardi…) dans le template.
    Scanne toute la feuille : une colonne de dates contient plusieurs labels de jour
    (un par semaine). Robuste quelle que soit la hauteur d'un slot (4 ou 6 lignes)."""
    jf_set = {'lundi','mardi','mercredi','jeudi','vendredi'}
    found = {}
    for ri in range(6, ws.max_row + 1):
        for ci in range(1, ws.max_column + 1):
            v = ws.cell(row=ri, column=ci).value
            if isinstance(v, str) and v.strip().lower() in jf_set:
                found[ci] = found.get(ci, 0) + 1
    # Garder les colonnes qui apparaissent plusieurs fois (vraies colonnes de dates)
    return sorted(c for c, cnt in found.items() if cnt >= 2)
# ─── Structure verticale du template ─────────────────────────────────────────
# Chaque jour occupe LIGNES_PAR_JOUR lignes. Une semaine = 5 jours + 1 séparateur.
# Tout le reste est dérivé de ces 3 valeurs (ne pas hardcoder ailleurs).
LIGNES_PAR_JOUR  = 6                                  # offsets: 0=sép,1=matin,2=label,3=num,4=pm,5=contenu
LIGNES_PAR_SEM   = 5 * LIGNES_PAR_JOUR + 1            # 5 jours + 1 séparateur de semaine
PREMIERE_LIGNE   = 6                                   # 1ère ligne de données (slot 0, offset 0)
# 25 slots = 5 semaines x 5 jours
SLOT_ROWS = [PREMIERE_LIGNE + (i // 5) * LIGNES_PAR_SEM + (i % 5) * LIGNES_PAR_JOUR for i in range(25)]
# Séparateurs de semaine (h=7.2) : juste après le 5e jour de chaque semaine.
# Le code n'utilise que 5 semaines actives (25 slots), mais le template physique
# en contient 6 (la 6e sert de "rab" supprimé dynamiquement selon le mois).
SEPS_SEMAINE = [PREMIERE_LIGNE + w * LIGNES_PAR_SEM + 5 * LIGNES_PAR_JOUR for w in range(5)]
# Dernière ligne du template = séparateur de la 6e (dernière) semaine physique
TEMPLATE_LAST_ROW = PREMIERE_LIGNE + 5 * LIGNES_PAR_SEM + 5 * LIGNES_PAR_JOUR  # = 191
# Offsets matin / après-midi pour le coloriage (matin = moitié haute, pm = moitié basse)
MATIN_OFFSETS = tuple(range(0, LIGNES_PAR_JOUR // 2))           # (0,1,2)
PM_OFFSETS    = tuple(range(LIGNES_PAR_JOUR // 2, LIGNES_PAR_JOUR))  # (3,4,5)
JOURS_FR_LIST = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi']

# Template vierge Septembre 2026 embarqué (base64) — ne plus charger depuis un fichier
_TEMPLATE_VIERGE_B64 = ""


# ─── Helpers ──────────────────────────────────────────────────────────────────
def colors_match(rgb):
    if not rgb: return False
    # Bleu standard #A6CAF0 ≈ RGB(166,202,240)
    if abs(rgb[0]-166)<20 and abs(rgb[1]-202)<20 and abs(rgb[2]-240)<20:
        return True
    # Bleu-vert / cyan clair #A0E0E0 ≈ RGB(160,224,224) (variante utilisée sur certains plannings)
    if abs(rgb[0]-160)<20 and abs(rgb[1]-224)<20 and abs(rgb[2]-224)<20:
        return True
    return False

def is_jaune(rgb):
    """True si la couleur est le jaune vif #FFFF00 (révision OU examen selon la légende)."""
    if not rgb: return False
    return abs(rgb[0]-255)<25 and abs(rgb[1]-255)<25 and rgb[2]<40

def _jaune_est_revision_xls(wb, ws):
    """Lit la légende d'un fichier .xls : True si une case jaune est étiquetée 'révision'.
    Retourne False si étiquetée 'examen', None si indéterminé. Par sécurité, seul True
    déclenche la conversion jaune -> jour de cours."""
    for r in range(ws.nrows):
        for c in range(ws.ncols):
            try:
                rgb = wb.colour_map.get(wb.xf_list[ws.cell_xf_index(r, c)].background.pattern_colour_index)
            except Exception:
                rgb = None
            if not is_jaune(rgb):
                continue
            for cc in range(c + 1, min(c + 5, ws.ncols)):
                v = ws.cell_value(r, cc)
                if isinstance(v, str) and v.strip():
                    low = _strip_accents(v).lower()
                    if 'revis' in low: return True
                    if 'exam' in low: return False
    return None

def cell_to_str(v):
    if v is None: return ''
    return str(v).strip()

def is_available(v):
    if v is None: return False
    return str(v).strip().upper() in ['X','4','✓','OUI','O']

def find_month_num(text):
    t = text.strip().lower()
    for m, mn in MOIS_ABBR.items():
        if m in t:
            yr = re.search(r'(20\d\d)', t)
            return mn, int(yr.group(1)) if yr else None
    return None, None

