def extraire_mois_feuilles(wb):
    """Retourne la liste des mois/années couverts par les feuilles du workbook."""
    couverts = []
    for sn in wb.sheetnames:
        for m_key, m_num in MOIS_ABBR.items():
            if m_key.upper() in sn.upper():
                y = re.search(r'(20\d\d)', sn)
                if y:
                    couverts.append({'mois': m_num, 'annee': int(y.group(1)), 'label': sn})
                    break
    return couverts

@app.route('/verifier-template', methods=['POST'])
def verifier_template():
    tf = request.files.get('template')
    if not tf:
        return jsonify({'mois_couverts': [], 'nb_feuilles': 0})
    try:
        wb = load_workbook(tf, read_only=True)
        mois = extraire_mois_feuilles(wb)
        nb   = len(wb.sheetnames)
        wb.close()
        return jsonify({'mois_couverts': mois, 'nb_feuilles': nb})
    except Exception as e:
        return jsonify({'mois_couverts': [], 'nb_feuilles': 0, 'error': str(e)})

@app.route('/analyser-coherence', methods=['POST'])
def analyser_coherence():
    """Dashboard : croise planning généré + tableau matière + dispos.
    Retourne heures par formateur, respect des dispos, manques par classe."""
    f_planning = request.files.get('planning')
    f_matiere  = request.files.get('matiere')
    f_dispos   = [request.files[k] for k in sorted(request.files) if k.startswith('dispo_')]
    if not (f_planning and f_matiere):
        return jsonify({'error': 'Planning et tableau matière requis'}), 400

    sid = str(uuid.uuid4())[:8]; wd = os.path.join(UPLOAD_FOLDER, sid); os.makedirs(wd, exist_ok=True)
    try:
        p_plan = os.path.join(wd, f_planning.filename or 'planning.xlsx'); f_planning.save(p_plan)
        p_mat  = os.path.join(wd, f_matiere.filename or 'matiere.xlsx');   f_matiere.save(p_mat)
        dispo_dir = os.path.join(wd, 'dispos'); os.makedirs(dispo_dir, exist_ok=True)
        for fd in f_dispos:
            if fd.filename: fd.save(os.path.join(dispo_dir, fd.filename))
        return jsonify(_calculer_coherence(p_plan, p_mat, dispo_dir))
    except Exception as e:
        import traceback
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500
    finally:
        shutil.rmtree(wd, ignore_errors=True)


def _calculer_coherence(p_plan, p_mat, dispo_dir):
    """Cœur de l'analyse : croise planning + tableau matière + dispos. Renvoie le dict résultat."""
    # 1. Prévu (tableau matière)
    aff = _auto_parse_formateurs(p_mat); aff.pop('_debug', None)
    prevu_prof = defaultdict(float); prevu_classe = defaultdict(float)
    for classe, affs in aff.items():
        for a in affs:
            prevu_prof[a['formateur']] += a['heures']
            prevu_classe[classe]       += a['heures']

    # 2. Dispos
    dispos = {}
    for f in sorted(glob.glob(os.path.join(dispo_dir, '*.xlsx'))):
        d = parse_disponibilite(f); dispos[d['nom']] = d['dispo']

    # 3. Planning placé
    placees_prof, placees_classe, creneaux, sans_prof_classe = _lire_planning_place(p_plan)

    # ── A. Heures par formateur ──
    formateurs = []
    for p in sorted(set(prevu_prof) | set(placees_prof), key=lambda x: -prevu_prof.get(x, 0)):
        if p == 'Pas de prof dispo': continue
        pv = round(prevu_prof.get(p, 0), 0); pl = round(placees_prof.get(p, 0), 0)
        has = any(noms_similaires(p, dn) for dn in dispos)
        if not has:            statut = 'sans_dispo'
        elif pl == 0:          statut = 'jamais_place'
        elif abs(pl-pv) <= 10: statut = 'ok'
        elif pl > pv:          statut = 'sur'
        else:                  statut = 'sous'
        formateurs.append({'nom': p, 'prevu': pv, 'place': pl, 'ecart': pl-pv, 'statut': statut})

    # ── B. Respect dispos ──
    ok = nondispo = sansfichier = 0; violations = []
    for ds, demi, prof, classe in creneaux:
        dn = next((n for n in dispos if noms_similaires(prof, n)), None)
        if dn is None: sansfichier += 1; continue
        jd = dispos[dn].get(ds, {})
        dispo = (jd.get('matin1') or jd.get('matin2')) if demi == 'matin' \
                else (jd.get('pm1') or jd.get('pm2'))
        if dispo: ok += 1
        else:
            nondispo += 1
            if len(violations) < 50:
                violations.append({'date': ds, 'demi': demi, 'prof': prof, 'classe': classe})

    # ── C. Manques par classe (aligner noms planning -> tableau) ──
    ref = list(prevu_classe.keys())
    def aligner(nom):
        return next((rc for rc in ref if noms_similaires(rc, nom)), nom)
    place_aligne = defaultdict(float)
    for cl, h in placees_classe.items(): place_aligne[aligner(cl)] += h
    sansp_aligne = defaultdict(float)
    for cl, h in sans_prof_classe.items(): sansp_aligne[aligner(cl)] += h
    classes = []
    for cl in sorted(set(prevu_classe) | set(place_aligne),
                     key=lambda x: -(prevu_classe.get(x,0) - place_aligne.get(x,0))):
        pv = round(prevu_classe.get(cl,0),0); pl = round(place_aligne.get(cl,0),0)
        classes.append({'classe': cl, 'prevu': pv, 'place': pl,
                        'manque': pv-pl, 'sans_prof': round(sansp_aligne.get(cl,0),0)})

    # ── D. Formateurs sans fichier dispo ──
    manquants = [{'nom': p, 'heures': round(prevu_prof[p],0)}
                 for p in prevu_prof if not any(noms_similaires(p, dn) for dn in dispos)]

    total = ok + nondispo + sansfichier

    # ── Ventilation du déficit (total prévu non placé) par cause ──────────────
    #   (a) sans_dispo  : heures de profs sans fichier de dispo → incompressible
    #                     tant qu'on ne fournit pas leurs dispos.
    #   (b) concurrence : le reste du déficit (profs qui ONT des dispos mais dont
    #                     toutes les heures n'ont pas pu être posées — chevauchement
    #                     de jours, créneaux disputés…). Réductible par r'affectation.
    total_prevu  = round(sum(prevu_prof.values()), 0)
    total_place  = round(sum(v for k, v in placees_prof.items() if k != 'Pas de prof dispo'), 0)
    deficit_total      = round(total_prevu - total_place, 0)
    deficit_sans_dispo = round(sum(m['heures'] for m in manquants), 0)
    deficit_concurrence = round(max(deficit_total - deficit_sans_dispo, 0), 0)

    return {
        'synthese': {
            'total_prevu':  total_prevu,
            'total_place':  total_place,
            'conformite_pct': round(100*ok/total, 1) if total else 0,
            'nb_violations': nondispo,
            'nb_sans_dispo': len(manquants),
            'nb_formateurs': len(formateurs),
            'deficit_total':       deficit_total,
            'deficit_sans_dispo':  deficit_sans_dispo,
            'deficit_concurrence': deficit_concurrence,
        },
        'formateurs': formateurs,
        'classes': classes,
        'violations': violations,
        'manquants': manquants,
    }


